const { runAnalystAgent } = require('/opt/node_modules/recon-multiagent/dist/analyst_agent.js');
const { persistSignals } = require('/opt/node_modules/recon-multiagent/dist/signal_writer.js');
const { getEvidenceByRunId, updateCoverageIteration } = require('/opt/node_modules/recon-multiagent/dist/db.js');
const { decideCoverage } = require('/opt/node_modules/recon-multiagent/dist/coverage.js');

const body = $input.first().json;
const runId = body.run_id;
const brief = body.brief;
const iteration = Number(body.iteration ?? 0);
const cap = Number($env.COVERAGE_MAX_ITERATIONS ?? 3);
const confidenceFloor = Number($env.COVERAGE_CONFIDENCE_FLOOR ?? 0.6);

if (!runId || !brief) {
  return [{ json: { statusCode: 400, body: { status: 'missing_run_id_or_brief' } } }];
}

const evidence = await getEvidenceByRunId(runId);

const analystResult = await runAnalystAgent(runId, brief, evidence, {
  baseUrl: $env.DEEPINFRA_BASE_URL,
  apiKey: $env.DEEPINFRA_API_KEY,
  model: $env.MODEL_NAME ?? 'google/gemma-4-26B-A4B-it',
  temperature: 0,
  confidenceFloor,
});

const persistResult = await persistSignals(runId, analystResult.signals);

// The coverage controller, not the model, owns the loop counter and hard cap.
const coverage = decideCoverage(brief, analystResult.signals, iteration, cap, confidenceFloor);

let action = coverage.action;
if (iteration >= cap) {
  action = 'proceed';
}

if (action === 'loop') {
  await updateCoverageIteration(runId, iteration + 1);
}

return [{ json: {
  statusCode: 200,
  body: {
    status: action === 'loop' ? 'loop' : 'proceed',
    run_id: runId,
    analyst: {
      signals: analystResult.signals.length,
      abstains: analystResult.abstainCount,
      repair_attempts: analystResult.repairAttempts,
      stopped: analystResult.stoppedBecause,
    },
    persist: {
      persisted_count: persistResult.persisted.length,
      failure_count: persistResult.failures.length,
    },
    coverage: {
      action,
      iteration: iteration + (action === 'loop' ? 1 : 0),
      unfilled_required: coverage.unfilled_required,
    },
  },
} }];
